2104 |     /**
2105 |      * Tries to parse JSON. If it fails due to bad escaping (common with AI),
2106 |      * it attempts to double-escape backslashes that aren't valid JSON control chars.
2107 |      */
2108 |     function smartJSONParse(jsonString) {
2109 |         try {
2110 |             return JSON.parse(jsonString);
2111 |         } catch (e) {
2112 |             console.warn("Standard JSON parse failed, attempting Robust Auto-Fix...");
2113 |             let fixed = jsonString
2114 |                 // 1. Fix backslashes that aren't part of a valid escape sequence
2115 |                 .replace(/\\(?!["\\/bfnrtu])/g, "\\\\")
2116 |                 // 2. Fix literal newlines inside strings (replace with \n)
2117 |                 .replace(/(\n)/g, (match, p1, offset) => {
2118 |                     // Only replace if we are likely inside a quoted string
2119 |                     const before = jsonString.slice(0, offset);
2120 |                     const quoteCount = (before.match(/"/g) || []).length;
2121 |                     return (quoteCount % 2 === 1) ? "\\n" : "\n";
2122 |                 });
2123 | 
2124 |             try {
2125 |                 const cleanObj = JSON.parse(fixed);
2126 |                 document.getElementById('json-input').value = fixed;
2127 |                 if (typeof saveState === 'function') saveState();
2128 |                 showGlobalToast("✨ Robust Auto-Correction Applied");
2129 |                 return cleanObj;
2130 |             } catch (e2) {
2131 |                 console.error("Robust fix failed:", e2);
