2376 |     // --- CLIENT SIDE PATCH ENGINE (Smart Line-Matcher) ---
2377 |     function applyLocalPatch(content, ops) {
2378 |         let lines = content.split('\n');
2379 |         let logs = [];
2380 |         let success = true;
2381 | 
2382 |         if (typeof ops === 'string') {
2383 |             try { ops = JSON.parse(ops); } catch(e) { return { content, success: false, logs: ["Invalid JSON"]}; }
2384 |         }
2385 | 
2386 |         ops.forEach(op => {
2387 |             if (op.action === 'comment') return;
2388 |             if (op.action === 'create_file') { lines = op.content.split('\n'); logs.push('Created file'); return; }
2389 |             
2390 |             if (op.action === 'replace_block') {
2391 |                 // Strategy 1: Exact String Match (Fastest)
2392 |                 const currentStr = lines.join('\n');
2393 |                 if (currentStr.includes(op.find_block)) {
2394 |                     lines = currentStr.replace(op.find_block, op.replace_with).split('\n');
2395 |                     logs.push('Exact match applied');
2396 |                     return;
2397 |                 }
2398 | 
2399 |                 // Strategy 2: Line-by-Line Fuzzy Match (Whitespace Agnostic)
2400 |                 const searchLines = op.find_block.split('\n').map(l => l.trim()).filter(l => l !== '');
2401 |                 if (searchLines.length === 0) return;
2402 | 
2403 |                 let matchStart = -1;
2404 |                 let matchEnd = -1;
2405 | 
2406 |                 // Scan file lines
2407 |                 for (let i = 0; i < lines.length; i++) {
2408 |                     // If first line matches (ignoring whitespace)
2409 |                     if (lines[i].trim() === searchLines[0]) {
2410 |                         // Check subsequent lines
2411 |                         let allMatch = true;
2412 |                         let fileOffset = 0;
2413 |                         let searchOffset = 1;
2414 |                         
2415 |                         while (searchOffset < searchLines.length) {
2416 |                             if (i + fileOffset + 1 >= lines.length) { allMatch = false; break; }
2417 |                             const nextFile = lines[i + fileOffset + 1].trim();
2418 |                             // Skip empty lines in file if they aren't in search block
2419 |                             if (nextFile === '') {
2420 |                                 fileOffset++;
2421 |                                 continue;
2422 |                             }
2423 |                             if (nextFile !== searchLines[searchOffset]) {
2424 |                                 allMatch = false;
2425 |                                 break;
2426 |                             }
2427 |                             fileOffset++;
2428 |                             searchOffset++;
2429 |                         }
2430 | 
2431 |                         if (allMatch) {
2432 |                             matchStart = i;
2433 |                             matchEnd = i + fileOffset;
2434 |                             break;
2435 |                         }
2436 |                     }
2437 |                 }
2438 | 
2439 |                 if (matchStart !== -1) {
2440 |                     // Replace the range of lines
2441 |                     const replacement = op.replace_with.split('\n');
2442 |                     lines.splice(matchStart, (matchEnd - matchStart) + 1, ...replacement);
2443 |                     logs.push(`Fuzzy match applied (Lines ${matchStart+1}-${matchEnd+1})`);
2444 |                 } else {
2445 |                     success = false;
2446 |                     logs.push(`Failed to find block: "${op.find_block.substring(0, 30)}..."`);
2447 |                     console.warn("Patch Mismatch. File has:", content.substring(0, 200), "... vs Search:", op.find_block);
2448 |                 }
2449 |             }
2450 |         });
2451 |         return { content: lines.join('\n'), success, logs };
2452 |     }
