2456 |     async function runAutoFixLoop(name, code, errorList) {
2457 |         const status = document.getElementById('ef-status-msg');
2458 |         let currentCode = code;
2459 |         let currentErrors = errorList;
2460 | 
2461 |         // Fix one by one (recursive loop)
2462 |         async function fixNext(index) {
2463 |             if (index >= currentErrors.length) return true; // All initial errors processed
2464 | 
2465 |             const err = currentErrors[index];
2466 |             status.innerText = `🔧 Fixing Error ${index + 1}/${currentErrors.length} (Line ${err.line})...`;
2467 |             status.style.color = "#eab308"; // Dev yellow
2468 | 
2469 |             try {
2470 |                 // 1. Get Patch from AI
2471 |                 const res = await fetch(CONFIG.funcUrl, { 
2472 |                     method: 'POST', 
2473 |                     headers: {'Content-Type': 'application/json'},
2474 |                     body: apiBody({ 
2475 |                         action: 'propose_syntax_fix', 
2476 |                         code: currentCode, 
2477 |                         error: err 
2478 |                     })
2479 |                 });
2480 |                 const data = await res.json();
2481 |                 const ops = data.operations;
2482 | 
2483 |                 if (!ops || ops === "[]") throw new Error("AI could not generate a fix.");
2484 | 
2485 |                 // 2. Apply Patch Locally
2486 |                 const patchResult = applyLocalPatch(currentCode, ops);
2487 |                 if (!patchResult.success) throw new Error("Generated patch did not match code.");
2488 | 
2489 |                 currentCode = patchResult.content;
2490 |                 document.getElementById('ef-code').value = currentCode; // Update UI
2491 | 
2492 |                 // 3. Re-Validate
2493 |                 const scanRes = await fetch(CONFIG.funcUrl, { 
2494 |                     method: 'POST', headers: {'Content-Type': 'application/json'},
2495 |                     body: apiBody({ action: 'validate_syntax_deep', code_block: currentCode, file_path: 'index.ts' })
2496 |                 });
2497 |                 const scanData = await scanRes.json();
2498 | 
2499 |                 if (scanData.valid) {
2500 |                     status.innerText = "✅ Syntax Fixed!";
2501 |                     return true;
2502 |                 } else {
2503 |                     // If errors remain, update list and Prompt user
2504 |                     currentErrors = scanData.errors;
2505 |                     if (confirm(`Fix applied, but ${currentErrors.length} errors remain. Continue fixing?`)) {
2506 |                         // Recursively fix the *new* first error (since layout changed)
2507 |                         return await fixNext(0);
2508 |                     } else {
2509 |                         return false;
2510 |                     }
2511 |                 }
2512 | 
2513 |             } catch (e) {
2514 |                 if (confirm(`Auto-Fix Failed: ${e.message}\n\nTry again?`)) {
2515 |                     return await fixNext(index);
2516 |                 } else {
2517 |                     return false;
2518 |                 }
2519 |             }
2520 |         }
2521 | 
2522 |         return await fixNext(0);
2523 |     }
