4303 |     async function executeRename() {
4304 |         const newPath = document.getElementById('rn-new-path').value.trim();
4305 |         const moveFolder = document.getElementById('rn-move-folder').checked;
4306 |         
4307 |         if (!newPath || newPath === currentRenamePath) return closeRenameModal();
4308 |         if (isPerformingAction) return;
4309 |         isPerformingAction = true;
4310 | 
4311 |         const getDir = (p) => p.substring(0, p.lastIndexOf('/') + 1);
4312 |         const oldDir = getDir(currentRenamePath);
4313 |         const newDir = getDir(newPath);
4314 | 
4315 |         showGlobalToast(moveFolder ? "Analyzing folder structure..." : "Preparing move...");
4316 | 
4317 |         try {
4318 |             let ops = [{ "action": "comment", "text": moveFolder ? `[Bulk Move] ${oldDir} -> ${newDir}` : `[Rename] ${currentRenamePath} -> ${newPath}` }];
4319 |             let filesToProcess = [];
4320 | 
4321 |             if (moveFolder && oldDir) {
4322 |                 // Find all siblings
4323 |                 filesToProcess = window.repoFiles.filter(f => f.path.startsWith(oldDir)).map(f => f.path);
4324 |             } else {
4325 |                 filesToProcess = [currentRenamePath];
4326 |             }
4327 | 
4328 |             // Concurrent Content Fetching
4329 |             const BATCH_SIZE = 5;
4330 |             for (let i = 0; i < filesToProcess.length; i += BATCH_SIZE) {
4331 |                 const batch = filesToProcess.slice(i, i + BATCH_SIZE);
4332 |                 const batchResults = await Promise.all(batch.map(async (path) => {
4333 |                     const res = await fetch(CONFIG.funcUrl, {
4334 |                         method: 'POST', headers: {'Content-Type': 'application/json'},
4335 |                         body: apiBody({ action: 'preview_file', file_path: path })
4336 |                     });
