4338 |                     return { path, content: b64DecodeUnicode(data.content || "") };
4339 |                 }));
4340 | 
4341 |                 batchResults.forEach(res => {
4342 |                     const targetPath = moveFolder ? res.path.replace(oldDir, newDir) : newPath;
4343 |                     ops.push({ "action": "delete_file", "file_path": res.path });
4344 |                     ops.push({ "action": "create_file", "file_path": targetPath, "content": res.content });
4345 |                 });
4346 |             }
4347 | 
4348 |             closeRenameModal();
4349 | 
4350 |             // 2. Load into Patcher
