5572 |     // --- GENERIC UI ---
5573 |     function formatBytes(bytes) {
5574 |         if (!bytes) return '0 B';
5575 |         const k = 1024;
5576 |         const sizes = ['B', 'KB', 'MB', 'GB'];
5577 |         const i = Math.floor(Math.log(bytes) / Math.log(k));
5578 |         return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
5579 |     }
