7750 |         checkboxes.forEach(cb => {
7751 |             const idx = dbHistory.findIndex(h => String(h.id) === String(cb.value));
7752 |             if (idx > oldestSelectedIndex) oldestSelectedIndex = idx;
7753 |         });
7754 | 
7755 |         // The target is the first record older than our selection that isn't also being deleted
7756 |         let rollbackTarget = null;
