5581 |     function timeAgo(dateString) {
5582 |         const date = new Date(dateString);
5583 |         const now = new Date();
5584 |         const seconds = Math.floor((now - date) / 1000);
5585 |         if (seconds < 10) return 'just now';
5586 |         if (seconds < 60) return seconds + 's ago';
5587 |         const minutes = Math.floor(seconds / 60);
5588 |         if (minutes < 60) return minutes + 'm ago';
5589 |         const hours = Math.floor(minutes / 60);
5590 |         if (hours < 24) return hours + 'h ago';
5591 |         return date.toLocaleDateString();
5592 |     }
