5820 |     async function jumpToElement(selector, tabId, navIndex, loadMoreFn) {
5821 |         console.group(`[DeepJump] Target: ${selector} in ${tabId}`);
5822 |         
5823 |         const navItems = document.querySelectorAll('.nav-item');
5824 |         switchTab(tabId, navItems[navIndex]);
5825 | 
5826 |         const scrollContainer = document.querySelector('.main-view');
5827 |         let retryCount = 0;
5828 |         const MAX_RETRIES = 5;
5829 | 
5830 |         const attemptNavigation = async () => {
5831 |             const element = document.querySelector(selector);
5832 |             
5833 |             if (element) {
5834 |                 console.log("[DeepJump] Element found. Scrolling...");
5835 |                 
5836 |                 // Wait for any tab transition animations
5837 |                 await new Promise(r => setTimeout(r, 300));
5838 | 
5839 |                 let offsetTop = 0;
5840 |                 let curr = element;
5841 |                 while (curr && curr !== scrollContainer) {
5842 |                     offsetTop += curr.offsetTop;
5843 |                     curr = curr.offsetParent;
5844 |                 }
5845 | 
5846 |                 const targetScroll = offsetTop - (scrollContainer.clientHeight / 2) + (element.clientHeight / 2);
5847 |                 scrollContainer.scrollTo({ top: targetScroll, behavior: 'smooth' });
5848 | 
5849 |                 // Visual Highlight
5850 |                 element.style.transition = 'all 0.5s ease';
5851 |                 element.style.backgroundColor = 'rgba(59, 130, 246, 0.3)';
5852 |                 element.style.boxShadow = '0 0 30px rgba(59, 130, 246, 0.6)';
5853 |                 setTimeout(() => {
5854 |                     element.style.backgroundColor = '';
5855 |                     element.style.boxShadow = '';
5856 |                 }, 3000);
5857 |                 
5858 |                 console.groupEnd();
5859 |                 return true;
5860 |             }
5861 | 
5862 |             if (retryCount < MAX_RETRIES && loadMoreFn) {
5863 |                 console.log(`[DeepJump] Not found. Triggering loadMore (Attempt ${retryCount + 1})...`);
5864 |                 retryCount++;
5865 |                 showGlobalToast("🔍 Searching deeper...");
5866 |                 
5867 |                 await loadMoreFn(); 
5868 |                 await new Promise(r => setTimeout(r, 800)); // Wait for render
5869 |                 return attemptNavigation();
5870 |             }
5871 | 
5872 |             console.error("[DeepJump] Failed: Element not found after retries.");
5873 |             showGlobalToast("Entry not found in recent history.", true);
5874 |             console.groupEnd();
5875 |             return false;
5876 |         };
5877 | 
5878 |         setTimeout(attemptNavigation, 100);
