7260 |                         const path = cleanChunk.substring(0, firstLineEnd).trim();
7261 |                         const content = cleanChunk.substring(firstLineEnd + 1);
7262 |                         if (path) pendingImportFiles.push({ path, content });
7263 |                     }
7264 |                 });
7265 |             } 
7266 |             else {
7267 |                 throw new Error("Unsupported file format. Use .zip or .txt exported from Conduit.");
7268 |             }
