7532 | 
7533 |             diffLeft.session.on('changeScrollTop', (top) => diffRight.session.setScrollTop(top));
7534 |             diffRight.session.on('changeScrollTop', (top) => diffLeft.session.setScrollTop(top));
7535 |             diffLeft.session.on('changeScrollLeft', (left) => diffRight.session.setScrollLeft(left));
7536 |             diffRight.session.on('changeScrollLeft', (left) => diffLeft.session.setScrollLeft(left));
7537 |         }
7538 | 
7539 |         diffLeft.setValue("Loading...", -1);
7540 |         diffRight.setValue("Loading...", -1);
7541 | 
7542 |         try {
7543 |             let leftContent = "", rightContent = "";
7544 | 
7545 |             if (forcedLeft !== null && forcedRight !== null) {
7546 |                 leftContent = forcedLeft;
7547 |                 rightContent = forcedRight;
7548 |             } else {
7549 |                 const rightRef = data.commit_sha || 'HEAD';
7550 |                 const leftRef = rightRef + '^';
7551 | 
7552 |                 const fetchFile = async (ref) => {
7553 |                     const res = await fetch(CONFIG.funcUrl, {
