7557 |                     const d = await res.json();
7558 |                     return d.content ? b64DecodeUnicode(d.content) : '';
7559 |                 };
7560 | 
7561 |                 const results = await Promise.all([
7562 |                     fetchFile(leftRef).catch(() => ""),
