7571 |             else if (data.file.endsWith('.html')) mode = "ace/mode/html";
7572 |             else if (data.file.endsWith('.css')) mode = "ace/mode/css";
7573 |             else if (data.file.endsWith('.json')) mode = "ace/mode/json";
7574 |             else if (data.file.endsWith('.md')) mode = "ace/mode/markdown";
