7581 | 
7582 |             const Range = ace.require('ace/range').Range;
7583 | 
7584 |             // Helper to get Range from String Index
7585 |             const getRangeFromText = (session, searchText) => {
7586 |                 const fullText = session.getValue();
7587 |                 // 1. Try Exact Match
7588 |                 let startIdx = fullText.indexOf(searchText);
7589 |                 
7590 |                 // 2. Try Robust Match (Ignoring Line Endings differences)
7591 |                 if (startIdx === -1) {
