8725 |     function extractTableNames(sql) {
8726 |         if (!sql) return [];
8727 |         const tables = [];
8728 |         const systemNoise = ['columns', 'tables', 'schemata', 'information_schema'];
8729 |         
8730 |         // Pattern 1: Standard FROM/JOIN (handles schema.table and "table")
8731 |         const fromRegex = /(?:FROM|JOIN)\s+(?:(?:"?\w+"?\.)?"?(\w+)"?)/gi;
8732 |         // Pattern 2: Metadata queries (WHERE table_name = '...')
8733 |         const metaRegex = /table_name\s*=\s*'([^']+)'/gi;
8734 | 
8735 |         let match;
8736 |         while ((match = fromRegex.exec(sql)) !== null) {
8737 |             const name = match[1];
8738 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
8739 |                 tables.push(name);
8740 |             }
8741 |         }
8742 |         
8743 |         while ((match = metaRegex.exec(sql)) !== null) {
8744 |             const name = match[1];
8745 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
8746 |                 tables.push(name);
8747 |             }
8748 |         }
8749 | 
8750 |         return tables;
8751 |     }
8752 | 
8753 |     function convertToCSV(resultObj) {
8754 |         const data = resultObj.data || [];
8755 |         if (!data.length) return '';
8756 |         
8757 |         const tables = extractTableNames(resultObj.sql);
8758 |         const metaHeader = tables.length > 0 ? `# Source Tables: ${tables.join(', ')}\n# Export Date: ${new Date().toISOString()}\n` : '';
8759 | 
8760 |         const headers = Object.keys(data[0]);
8761 |         const rows = data.map(row => 
8762 |             headers.map(header => {
8763 |                 let cell = row[header] === null || row[header] === undefined ? '' : row[header];
8764 |                 if (typeof cell === 'object') cell = JSON.stringify(cell);
8765 |                 return '"' + String(cell).replace(/"/g, '""') + '"';
8766 |             }).join(',')
8767 |         );
8768 |         return metaHeader + [headers.join(','), ...rows].join('\n');
8769 |     }
